styles:
    *,
    *::before,
    *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    :root {
      --sidebar-bg: #DAE4F8;
      --main-bg: #FFFCF8;
      --blue: #448AFF;
      --blue-dark: #3a7aee;
      --text: #1a1a1a;
      --muted: #6b6b6b;
      --border: #448AFF;
      --sidebar-width: 248px;
      --font: 'Montserrat', sans-serif;
    }

    html,
    body {
      height: 100%;
    }

    body {
      font-family: var(--font);
      background: var(--main-bg);
      color: var(--text);
      -webkit-font-smoothing: antialiased;
    }

    .app {
      display: flex;
      min-height: 100vh;
    }

    /* ── Sidebar ── */
    .sidebar {
      width: var(--sidebar-width);
      flex-shrink: 0;
      background: var(--sidebar-bg);
      display: flex;
      flex-direction: column;
      padding: 28px 20px 32px;
      min-height: 100vh;
      transition: width 0.22s ease, padding 0.22s ease;
      position: relative;
    }

    .sidebar__collapse {
      position: absolute;
      top: 14px;
      right: 12px;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 0;
      transition: background 0.15s ease;
    }

    .sidebar__collapse:hover {
      background: rgba(68, 138, 255, 0.12);
    }

    .sidebar__collapse svg {
      width: 22px;
      height: 22px;
      display: block;
    }

    .app.is-sidebar-collapsed .sidebar__collapse {
      display: none;
    }

    .sidebar__toggle {
      width: 54px;
      height: 54px;
      margin: 0 auto 18px;
      border: none;
      border-radius: 16px;
      background: rgba(68, 138, 255, 0.12);
      display: none;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: background 0.15s ease;
    }

    .app.is-sidebar-collapsed .sidebar__toggle {
      display: flex;
    }

    .sidebar__toggle:hover {
      background: rgba(68, 138, 255, 0.18);
    }

    .sidebar__toggle img {
      width: 32px;
      height: 32px;
      object-fit: contain;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
    }

    .sidebar__brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      margin-bottom: 36px;
    }

    .sidebar__logo {
      width: 120px;
      height: auto;
      display: block;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
      margin-bottom: 4px;
    }

    .sidebar__title {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      letter-spacing: 0.06em;
    }

    .nav {
      list-style: none;
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .nav a {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 12px 16px;
      border-radius: 12px;
      color: var(--blue);
      font-size: 14px;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .nav a svg {
      width: 20px;
      height: 20px;
      flex-shrink: 0;
      stroke: currentColor;
      fill: none;
    }

    .nav a:hover:not(.is-active) {
      background: rgba(68, 138, 255, 0.12);
    }

    .nav a.is-active {
      background: var(--blue);
      color: #fff;
    }

    .nav a.is-active svg {
      stroke: #fff;
    }
    .nav a .nav-icon--saved { stroke: none; }
    .nav a .nav-icon--saved path { fill: currentColor; }
    .nav a .nav-icon--attendance { stroke: none; }
    .nav a .nav-icon--attendance path { fill: currentColor; }
    .nav a .nav-icon--events { stroke: none; }
    .nav a .nav-icon--events path { fill: currentColor; }
    .nav a .nav-icon--home { stroke: none; }
    .nav a .nav-icon--home path { fill: currentColor; }
    .nav a .nav-icon--certificates { stroke: none; }
    .nav a .nav-icon--certificates path { fill: currentColor; }
    .nav a.is-active [class*="nav-icon--"] > g { filter: none; }

    .sidebar__spacer {
      flex: 1;
      min-height: 24px;
    }

    .nav--bottom {
      margin-top: auto;
      padding-top: 16px;
    }

    .app.is-sidebar-collapsed .sidebar {
      width: 102px;
      padding: 28px 12px 24px;
    }

    .app.is-sidebar-collapsed .sidebar__brand {
      display: none;
    }

    .app.is-sidebar-collapsed .nav a {
      justify-content: center;
      gap: 0;
      padding: 14px 0;
      font-size: 0;
    }

    .app.is-sidebar-collapsed .nav a svg {
      width: 24px;
      height: 24px;
    }

    .app.is-sidebar-collapsed .nav a.is-active {
      width: 56px;
      margin: 0 auto;
    }

    /* ── Main ── */
    .main {
      flex: 1;
      min-width: 0;
      overflow-y: auto;
      padding: 32px 40px 48px;
    }

    .main__header {
      position: relative;
      margin-bottom: 36px;
    }

    .main__header-bg {
      position: absolute;
      inset: -28px -40px 0 -24px;
      pointer-events: none;
      overflow: hidden;
      z-index: 0;
    }

    .main__blob {
      position: absolute;
      border-radius: 50%;
    }

    .main__blob--blue {
      width: 300px;
      height: 300px;
      top: -110px;
      right: 80px;
      background: rgba(174, 203, 255, 0.5);
    }

    .main__blob--cream {
      width: 220px;
      height: 220px;
      top: -50px;
      right: -30px;
      background: rgba(255, 238, 213, 0.75);
    }

    .main__blob--soft {
      width: 180px;
      height: 180px;
      top: 40px;
      left: 38%;
      background: rgba(218, 228, 248, 0.85);
    }

    .main__top {
      position: relative;
      z-index: 1;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 22px;
    }

    .main__greeting {
      font-size: clamp(1.75rem, 3vw, 2.25rem);
      font-weight: 700;
      color: var(--blue);
      line-height: 1.15;
    }

    .main__tools {
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .main__user-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--blue);
      white-space: nowrap;
    }

    .tool-btn {
      width: 40px;
      height: 40px;
      border: none;
      border-radius: 50%;
      background: #e8eef6;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
      transition: background 0.15s ease;
    }

    .tool-btn:hover {
      background: rgba(68, 138, 255, 0.18);
    }

    .tool-btn--avatar {
      background: #c5d9fc;
    }

    .tool-btn--help { background: #c5d9fc; color: #fff; }
    .tool-btn--help:hover { background: #b5cffc; color: #fff; }
    .tool-btn--help svg { width: 22px; height: 22px; flex-shrink: 0; }

    .tool-btn svg {
      width: 22px;
      height: 22px;
    }

    .search-bar {
      position: relative;
      z-index: 1;
      padding: 4px 0;
    }

    .search-bar__field {
      width: 100%;
      display: flex;
      align-items: center;
      gap: 10px;
      height: 40px;
      padding: 0 18px;
      background: rgba(68, 138, 255, 0.12);
      border: 1px solid rgba(68, 138, 255, 0.22);
      border-radius: 999px;
    }

    .search-bar__field svg {
      width: 16px;
      height: 16px;
      color: var(--blue);
      flex-shrink: 0;
      opacity: 0.7;
    }

    .search-bar__field input {
      flex: 1;
      border: none;
      outline: none;
      font-family: var(--font);
      font-size: 13px;
      color: var(--text);
      background: transparent;
    }

    .search-bar__field input::placeholder {
      color: rgba(68, 138, 255, 0.55);
      font-weight: 500;
    }

    /* ── Explore sections ── */
    .explore-section {
      margin-bottom: 36px;
    }

    .explore-section:last-child {
      margin-bottom: 0;
    }

    .section-head {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      margin-bottom: 16px;
    }

    .section-head h2 {
      font-size: 18px;
      font-weight: 700;
      color: var(--text);
    }

    .section-head__more {
      width: 28px;
      height: 28px;
      border: none;
      border-radius: 50%;
      background: var(--blue);
      color: #fff;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .section-head__more:hover {
      background: var(--blue-dark);
    }

    .section-head__more svg {
      width: 14px;
      height: 14px;
    }

    .event-row {
      display: flex;
      gap: 20px;
      overflow-x: auto;
      padding: 8px 0 14px;
      scroll-snap-type: x proximity;
      scrollbar-width: none;
      -ms-overflow-style: none;
    }

    .event-row::-webkit-scrollbar {
      display: none;
    }

    /* ── Event card ── */
    .event-card {
      flex: 0 0 272px;
      scroll-snap-align: start;
      display: flex;
      flex-direction: column;
      min-height: 224px;
      background: #fff;
      border: 1.5px solid transparent;
      border-radius: 16px;
      overflow: hidden;
      cursor: pointer;
      box-shadow: 0 8px 24px rgba(0, 40, 90, 0.08);
      transition: border-color 0.18s ease, box-shadow 0.18s ease, transform 0.18s ease;
    }

    .event-card:hover {
      border-color: var(--blue);
      box-shadow: 0 12px 30px rgba(68, 138, 255, 0.16);
    }

    .event-card__media {
      position: relative;
      height: 108px;
      flex-shrink: 0;
      background: linear-gradient(135deg, #e8eef8 0%, #d4e2f7 100%);
      border-bottom: 1px solid rgba(68, 138, 255, 0.12);
    }

    .event-card__bookmark {
      position: absolute;
      top: 10px;
      right: 10px;
      width: 28px;
      height: 28px;
      border: none;
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.9);
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .event-card__bookmark svg {
      width: 16px;
      height: 16px;
    }

    .event-card__body {
      display: flex;
      gap: 16px;
      flex: 1;
      padding: 14px 16px 16px;
    }

    .event-card__date {
      flex-shrink: 0;
      width: 56px;
      text-align: center;
      font-weight: 700;
      line-height: 1.1;
    }

    .event-card__date-month {
      display: block;
      font-size: 11px;
      text-transform: uppercase;
      color: var(--text);
      letter-spacing: 0.04em;
    }

    .event-card__date-day {
      display: block;
      font-size: 28px;
      color: var(--blue);
      line-height: 1;
      margin: 2px 0;
    }

    .event-card__date-year {
      display: block;
      font-size: 11px;
      color: var(--muted);
      font-weight: 600;
    }

    .event-card__info {
      flex: 1;
      min-width: 0;
      display: flex;
      flex-direction: column;
    }

    .event-card__name {
      font-size: 14px;
      font-weight: 700;
      color: var(--text);
      margin-bottom: 6px;
      line-height: 1.35;
      display: -webkit-box;
      -webkit-line-clamp: 2;
      -webkit-box-orient: vertical;
      overflow: hidden;
    }

    .event-card__venue {
      font-size: 12px;
      font-weight: 600;
      color: var(--blue);
      margin: 0;
    }

    .event-card__time {
      font-size: 12px;
      color: var(--muted);
      margin: 0;
    }

    @media (max-width: 900px) {
      .app {
        flex-direction: column;
      }

      .sidebar {
        width: 100%;
        min-height: auto;
        flex-direction: row;
        flex-wrap: wrap;
        padding: 20px;
      }

      .sidebar__brand {
        flex-direction: row;
        gap: 12px;
        margin-bottom: 0;
        width: 100%;
      }

      .sidebar__toggle,
      .sidebar__collapse {
        display: none !important;
      }

      .nav {
        flex-direction: row;
        flex-wrap: wrap;
        width: 100%;
      }

      .sidebar__spacer,
      .nav--bottom {
        display: none;
      }

      .main__user-name {
        display: none;
      }

      .app.is-sidebar-collapsed .sidebar {
        width: 100%;
        padding: 20px;
      }

      .app.is-sidebar-collapsed .sidebar__brand {
        display: flex;
      }

      .app.is-sidebar-collapsed .nav a {
        font-size: 14px;
        gap: 12px;
        padding: 12px 16px;
        justify-content: flex-start;
      }

      .app.is-sidebar-collapsed .nav a.is-active {
        width: auto;
        margin: 0;
      }

      .main {
        padding: 24px 20px 40px;
      }

      .main__header-bg {
        inset: -20px -20px 0 -16px;
      }

      .event-card {
        flex: 0 0 240px;
      }
    }

